"use client";

import { cn } from "@/lib/utils";
import type { ThemeEntry } from "@/types/theme";

interface ThemeCardProps {
  theme: ThemeEntry;
  isActive: boolean;
  onClick: () => void;
  disabled?: boolean;
}

export function ThemeCard({
  theme,
  isActive,
  onClick,
  disabled,
}: ThemeCardProps) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      className={cn(
        "group relative flex flex-col overflow-hidden rounded-lg border text-left transition-all",
        isActive
          ? "border-accent ring-2 ring-accent/30"
          : "border-border hover:border-muted"
      )}
    >
      {/* Color preview strip */}
      <div
        className="flex h-20 items-center justify-between px-4"
        style={{ backgroundColor: theme.preview.background }}
      >
        <span
          className="text-sm font-medium"
          style={{ color: theme.preview.foreground }}
        >
          Aa
        </span>
        <div className="flex gap-1.5">
          <div
            className="h-4 w-4 rounded-full"
            style={{ backgroundColor: theme.preview.accent }}
          />
          <div
            className="h-4 w-4 rounded-full"
            style={{ backgroundColor: theme.preview.foreground, opacity: 0.4 }}
          />
        </div>
      </div>

      {/* Info */}
      <div className="flex items-center justify-between bg-surface px-3 py-2">
        <div className="min-w-0">
          <p className="truncate text-sm font-medium text-foreground">
            {theme.name}
          </p>
          <p className="truncate text-xs text-muted">{theme.author}</p>
        </div>
        {isActive && (
          <div className="ml-2 h-2 w-2 shrink-0 rounded-full bg-accent" />
        )}
      </div>
    </button>
  );
}

