function official(
  id: string,
  name: string,
  type: "dark" | "light",
  preview: ThemeEntry["preview"]
): ThemeEntry {
  return {
    id,
    name,
    type,
    source: "official",
    author: "Omarchy",
    colorFileUrl: `${OMARCHY_BASE}/${id}/colors.toml`,
    colorFormat: "colors-toml",
    preview,
  };
}

function community(
  id: string,
  name: string,
  type: "dark" | "light",
  author: string,
  repo: string,
  branch: string,
  preview: ThemeEntry["preview"],
  format: ThemeEntry["colorFormat"] = "alacritty-toml"
): ThemeEntry {
  const file = format === "colors-toml" ? "colors.toml" : "alacritty.toml";
  return {
    id,
    name,
    type,
    source: "community",
    author,
    colorFileUrl: `https://raw.githubusercontent.com/${repo}/${branch}/${file}`,
    colorFormat: format,
    preview,
  };
}

