 56→export function ThemeProvider({ children }: { children: React.ReactNode }) {
 57→  const [activeThemeId, setActiveThemeId] = useState<string | null>(null);
 58→  const [loading, setLoading] = useState(false);
 59→
 60→  // On mount: restore cached theme immediately to avoid flash
 61→  useLayoutEffect(() => {
 62→    const savedId = localStorage.getItem(STORAGE_KEY);
 63→    const savedColors = localStorage.getItem(COLORS_STORAGE_KEY);
 64→    if (savedId && savedColors) {
 65→      try {
 66→        const colors = JSON.parse(savedColors) as AppThemeColors;
 67→        setColorVars(colors);
 68→        setActiveThemeId(savedId);
 69→      } catch {
 70→        localStorage.removeItem(STORAGE_KEY);
 71→        localStorage.removeItem(COLORS_STORAGE_KEY);
 72→      }
 73→    }
 74→  }, []);
 75→
 76→  const applyTheme = useCallback(async (themeId: string) => {
 77→    setLoading(true);
 78→    try {
 79→      const res = await fetch(`/api/themes/${themeId}/colors`);
 80→      if (!res.ok) throw new Error("Failed to fetch theme");
 81→      const colors: AppThemeColors = await res.json();
 82→      setColorVars(colors);
 83→      localStorage.setItem(STORAGE_KEY, themeId);
 84→      localStorage.setItem(COLORS_STORAGE_KEY, JSON.stringify(colors));
 85→      setActiveThemeId(themeId);
 86→    } catch (err) {
 87→      console.error("Failed to apply theme:", err);
 88→    } finally {
 89→      setLoading(false);
 90→    }
 91→  }, []);
 92→
 93→  const resetTheme = useCallback(() => {
 94→    clearColorVars();
 95→    localStorage.removeItem(STORAGE_KEY);
 96→    localStorage.removeItem(COLORS_STORAGE_KEY);
 97→    setActiveThemeId(null);
 98→  }, []);
 99→
100→  return (
101→    <ThemeContext.Provider
102→      value={{ activeThemeId, loading, applyTheme, resetTheme }}
103→    >
104→      {children}
105→    </ThemeContext.Provider>
106→  );
107→}
