"use client";

import { useState, useMemo } from "react";
import { SearchInput } from "@/components/ui/search-input";
import { ThemeCard, DefaultThemeCard } from "@/components/ui/theme-card";
import { useTheme } from "@/components/providers/theme-provider";
import { themeRegistry, getThemeById } from "@/lib/themes/registry";
import { cn } from "@/lib/utils";

type Filter = "all" | "dark" | "light";

export default function SettingsPage() {
  const {
    activeThemeId,
    loading,
    backgroundEnabled,
    backgroundUrl,
    applyTheme,
    resetTheme,
    setBackgroundUrl,
    toggleBackground,
  } = useTheme();
  const [search, setSearch] = useState("");
  const [filter, setFilter] = useState<Filter>("all");

  const filtered = useMemo(() => {
    return themeRegistry.filter((t) => {
      if (filter !== "all" && t.type !== filter) return false;
      if (search) {
        const q = search.toLowerCase();
        return (
          t.name.toLowerCase().includes(q) ||
          t.author.toLowerCase().includes(q)
        );
      }
      return true;
    });
  }, [search, filter]);

  const activeTheme = activeThemeId ? getThemeById(activeThemeId) : null;
  const backgrounds = activeTheme?.backgroundImages ?? [];

  const filters: { label: string; value: Filter }[] = [
    { label: "All", value: "all" },
    { label: "Dark", value: "dark" },
    { label: "Light", value: "light" },
  ];

  return (
    <div className="mx-auto max-w-5xl">
      <h1 className="text-2xl font-semibold text-foreground">Settings</h1>
      <p className="mt-1 text-sm text-muted">Customize your dashboard theme</p>

      {/* ── Theme Section ──────────────────────────────────── */}
      <div className="mt-8">
        <h2 className="text-lg font-medium text-foreground">Theme</h2>
        <p className="mt-1 text-sm text-muted">
          Choose from {themeRegistry.length} OMARCHY themes
        </p>

        {/* Search + filters */}
        <div className="mt-4 flex flex-col gap-3 sm:flex-row sm:items-center">
          <SearchInput
            value={search}
            onChange={setSearch}
            placeholder="Search themes..."
            className="sm:w-72"
          />
          <div className="flex gap-1 rounded-lg border border-border bg-surface p-1">
            {filters.map((f) => (
              <button
                key={f.value}
                onClick={() => setFilter(f.value)}
                className={cn(
                  "rounded-md px-3 py-1 text-sm font-medium transition-colors",
                  filter === f.value
                    ? "bg-accent/15 text-accent-light"
                    : "text-muted hover:text-foreground"
                )}
              >
                {f.label}
              </button>
            ))}
          </div>
        </div>

        {/* Theme grid */}
        <div className="mt-6 grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4">
          <DefaultThemeCard
            isActive={activeThemeId === null}
            onClick={resetTheme}
          />
          {filtered.map((theme) => (
            <ThemeCard
              key={theme.id}
              theme={theme}
              isActive={activeThemeId === theme.id}
              disabled={loading}
              onClick={() => applyTheme(theme.id)}
            />
          ))}
        </div>

        {filtered.length === 0 && (
          <p className="mt-8 text-center text-sm text-muted">
            No themes match your search.
          </p>
        )}
      </div>

      {/* ── Wallpaper Section ──────────────────────────────── */}
      {backgrounds.length > 0 && (
        <div className="mt-10">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-lg font-medium text-foreground">
                Background Image
              </h2>
              <p className="mt-1 text-sm text-muted">
                Use a wallpaper from the {activeTheme?.name} theme
              </p>
            </div>
            <button
              onClick={toggleBackground}
              className={cn(
                "relative inline-flex h-6 w-11 shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors",
                backgroundEnabled ? "bg-accent" : "bg-surface-light"
              )}
              role="switch"
              aria-checked={backgroundEnabled}
            >
              <span
                className={cn(
                  "pointer-events-none inline-block h-5 w-5 rounded-full bg-white shadow-sm transition-transform",
                  backgroundEnabled ? "translate-x-5" : "translate-x-0"
                )}
              />
            </button>
          </div>

          <div className="mt-4 grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4">
            {backgrounds.map((url) => (
              <button
                key={url}
                onClick={() => setBackgroundUrl(url)}
                className={cn(
                  "group relative h-28 overflow-hidden rounded-lg border transition-all",
                  backgroundUrl === url && backgroundEnabled
                    ? "border-accent ring-2 ring-accent/30"
                    : "border-border hover:border-muted"
                )}
              >
                {/* eslint-disable-next-line @next/next/no-img-element */}
                <img
                  src={url}
                  alt="Background option"
                  className="h-full w-full object-cover transition-transform duration-300 group-hover:scale-105"
                  loading="lazy"
                />
              </button>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

