  1→"use client";
  2→
  3→import {
  4→  createContext,
  5→  useCallback,
  6→  useContext,
  7→  useLayoutEffect,
  8→  useState,
  9→} from "react";
 10→import type { AppThemeColors, AppThemeColorKey } from "@/types/theme";
 11→import { DEFAULT_COLORS } from "@/types/theme";
 12→import { isLightColor } from "@/lib/themes/color-utils";
 13→
 14→const STORAGE_KEY = "partio-theme-id";
 15→const COLORS_STORAGE_KEY = "partio-theme-colors";
 16→const BG_ENABLED_KEY = "partio-bg-enabled";
 17→const BG_URL_KEY = "partio-bg-url";
 18→
 19→interface ThemeContextValue {
 20→  activeThemeId: string | null;
 21→  loading: boolean;
 22→  backgroundEnabled: boolean;
 23→  backgroundUrl: string | null;
 24→  applyTheme: (themeId: string) => Promise<void>;
 25→  resetTheme: () => void;
 26→  setBackgroundUrl: (url: string) => void;
 27→  toggleBackground: () => void;
 28→}
 29→
 30→const ThemeContext = createContext<ThemeContextValue>({
 31→  activeThemeId: null,
 32→  loading: false,
 33→  backgroundEnabled: false,
 34→  backgroundUrl: null,
 35→  applyTheme: async () => {},
 36→  resetTheme: () => {},
 37→  setBackgroundUrl: () => {},
 38→  toggleBackground: () => {},
 39→});
 40→
 41→function setColorVars(colors: AppThemeColors) {
 42→  const root = document.documentElement;
 43→  for (const [key, value] of Object.entries(colors)) {
 44→    root.style.setProperty(`--${key}`, value);
 45→  }
 46→  if (isLightColor(colors.background)) {
 47→    root.classList.remove("dark");
 48→    root.classList.add("light");
 49→  } else {
 50→    root.classList.remove("light");
 51→    root.classList.add("dark");
 52→  }
 53→}
 54→
 55→function clearColorVars() {
 56→  const root = document.documentElement;
 57→  for (const key of Object.keys(DEFAULT_COLORS)) {
 58→    root.style.removeProperty(`--${key as AppThemeColorKey}`);
 59→  }
 60→  root.classList.remove("light");
 61→  root.classList.add("dark");
 62→}
 63→
 64→function applyWallpaper(url: string | null, enabled: boolean) {
 65→  const body = document.body;
 66→  const root = document.documentElement;
 67→  if (enabled && url) {
 68→    body.style.backgroundImage = `url(${url})`;
 69→    root.setAttribute("data-wallpaper", "");
 70→  } else {
 71→    body.style.backgroundImage = "";
 72→    root.removeAttribute("data-wallpaper");
 73→  }
 74→}
 75→
 76→export function ThemeProvider({ children }: { children: React.ReactNode }) {
 77→  const [activeThemeId, setActiveThemeId] = useState<string | null>(null);
 78→  const [loading, setLoading] = useState(false);
 79→  const [backgroundEnabled, setBackgroundEnabled] = useState(false);
 80→  const [backgroundUrl, setBackgroundUrlState] = useState<string | null>(null);
 81→
 82→  // On mount: restore cached theme + wallpaper immediately
 83→  useLayoutEffect(() => {
 84→    const savedId = localStorage.getItem(STORAGE_KEY);
 85→    const savedColors = localStorage.getItem(COLORS_STORAGE_KEY);
 86→    if (savedId && savedColors) {
 87→      try {
 88→        const colors = JSON.parse(savedColors) as AppThemeColors;
 89→        setColorVars(colors);
 90→        setActiveThemeId(savedId);
 91→      } catch {
 92→        localStorage.removeItem(STORAGE_KEY);
