@import "tailwindcss";

:root {
  transition: background-color 0.3s ease, color 0.3s ease;
  --background: #0a0a0b;
  --foreground: #e5e5e5;
  --muted: #a1a1aa;
  --accent: #7B2D8E;
  --accent-light: #9B4DB0;
  --accent-dark: #5E1F6E;
  --surface: #111113;
  --surface-light: #1a1a1e;
  --border: #27272a;
  --success: #22c55e;
  --warning: #eab308;
  --accent-orange: #d97706;
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-muted: var(--muted);
  --color-accent: var(--accent);
  --color-accent-light: var(--accent-light);
  --color-accent-dark: var(--accent-dark);
  --color-surface: var(--surface);
  --color-surface-light: var(--surface-light);
  --color-border: var(--border);
  --color-success: var(--success);
  --color-warning: var(--warning);
  --color-accent-orange: var(--accent-orange);
  --font-sans: var(--font-inter);
  --font-mono: var(--font-jetbrains-mono);
}

body {
  background-color: var(--background);
  background-size: cover;
  background-attachment: fixed;
  background-position: center;
  color: var(--foreground);
  font-family: var(--font-sans), system-ui, sans-serif;
}

/* When wallpaper is active, make main content area semi-transparent */
html[data-wallpaper] [data-dashboard-bg] {
  background-color: color-mix(in srgb, var(--background) 80%, transparent);
}

::selection {
  background: var(--accent);
  color: white;
}

/* Scrollbar styling */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: var(--surface);
}

::-webkit-scrollbar-thumb {
  background: var(--border);
  border-radius: 3px;
}

import { Sidebar } from "@/components/layout/sidebar";
import { Topbar } from "@/components/layout/topbar";

export default function DashboardLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  return (
    <div className="min-h-screen bg-background" data-dashboard-bg>
      <Sidebar />
      <div className="pl-60">
        <Topbar />
        <main className="p-6">{children}</main>
      </div>
    </div>
  );
}

