              isActive={activeThemeId === theme.id}
              disabled={loading}
              onClick={() => applyTheme(theme.id)}
            />
          ))}
        </div>

        {filtered.length === 0 && (
          <p className="mt-8 text-center text-sm text-muted">
            No themes match your search.
          </p>
        )}
      </div>
    </div>
  );
}

